print(f"Number of stabilizers: {len(stabilizers)}")
print(f"Length of first stabilizer: {len(stabilizers[0])}")

try:
    tableau = stim.Tableau.from_stabilizers([stim.PauliString(s) for s in stabilizers], allow_redundant=True, allow_underconstrained=True)
    circuit = tableau.to_circuit(method="graph_state")
    
    # Check for RX and replace with H if necessary
    # RX 0 means reset qubit 0 to |+>. H 0 does |0> -> |+>
    # If the circuit starts with RX, and we assume |0> input, we can replace RX with H.
    
    # We will do a string replacement on the circuit text.
    circuit_str = str(circuit)
    circuit_str = circuit_str.replace("RX", "H")
    
    # Also MPP is not allowed in most basic gate sets for this problem unless necessary.
    # graph_state synthesis usually produces: RX (init), CZ (entangle), H/S/sqrtX (local clifford), M (measurement - maybe not).
    # It shouldn't produce measurements for a stabilizer state preparation circuit.
    
    print(circuit_str)
    
except Exception as e:
    print(f"Error: {e}")
